// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_Q 200005
#define MAX_COLOR 1000000005

// Segment tree node structure
typedef struct {
    int maxDeliciousness;
    int minDeliciousness;
} SegmentTreeNode;

// Function to update the segment tree
void updateSegmentTree(SegmentTreeNode* tree, int node, int start, int end, int index, int value) {
    if (start == end) {
        tree[node].maxDeliciousness = value;
        tree[node].minDeliciousness = value;
    } else {
        int mid = (start + end) / 2;
        if (index <= mid) {
            updateSegmentTree(tree, 2 * node, start, mid, index, value);
        } else {
            updateSegmentTree(tree, 2 * node + 1, mid + 1, end, index, value);
        }
        tree[node].maxDeliciousness = tree[2 * node].maxDeliciousness + tree[2 * node + 1].maxDeliciousness;
        tree[node].minDeliciousness = tree[2 * node].minDeliciousness + tree[2 * node + 1].minDeliciousness;
    }
}

// Function to query the segment tree
int querySegmentTree(SegmentTreeNode* tree, int node, int start, int end, int left, int right) {
    if (left > end || right < start) {
        return 0;
    }
    if (left <= start && right >= end) {
        return tree[node].maxDeliciousness;
    }
    int mid = (start + end) / 2;
    int leftQuery = querySegmentTree(tree, 2 * node, start, mid, left, right);
    int rightQuery = querySegmentTree(tree, 2 * node + 1, mid + 1, end, left, right);
    return leftQuery + rightQuery;
}

int main() {
    int Q, K;
    scanf("%d %d", &Q, &K);
    SegmentTreeNode* tree = (SegmentTreeNode*)malloc(4 * MAX_Q * sizeof(SegmentTreeNode));
    int ans = 0;
    for (int i = 0; i < Q; i++) {
        int b, C, d;
        scanf("%d %d", &b, &C);
        if (b == 1 || b == 2) {
            scanf("%d", &d);
            int c = C ^ ans;
            updateSegmentTree(tree, 1, 0, MAX_COLOR, c, d);
        } else {
            int c = C ^ ans;
            int maxDeliciousness = querySegmentTree(tree, 1, 0, MAX_COLOR, c - K, c + K);
            printf("%d\n", maxDeliciousness);
            ans = maxDeliciousness;
        }
    }
    return 0;
}

